/**
 * Authentication Rate Limiting Module
 *
 * Provides rate limiting for failed authentication attempts.
 */

import type { RateLimitEntry } from './types.js'

// Constants
const RATE_LIMIT_MAX_ATTEMPTS = 5
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000 // 15 minutes
const RATE_LIMIT_BLOCK_DURATION_MS = 15 * 60 * 1000 // 15 minutes

const rateLimitStore = new Map<string, RateLimitEntry>()

/**
 * Check if an IP is rate limited
 * Returns { allowed: boolean, retryAfter?: number }
 */
export function checkRateLimit(ip: string): { allowed: boolean; retryAfter?: number } {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    return { allowed: true }
  }

  // Check if currently blocked
  if (entry.blockedUntil && entry.blockedUntil > now) {
    return {
      allowed: false,
      retryAfter: Math.ceil((entry.blockedUntil - now) / 1000)
    }
  }

  // Check if window has expired - reset if so
  if (now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.delete(ip)
    return { allowed: true }
  }

  return { allowed: true }
}

/**
 * Record a failed authentication attempt for an IP
 * Returns true if the IP is now blocked
 */
export function recordFailedAuth(ip: string): boolean {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Reset if window has expired
  if (now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Increment attempts
  entry.attempts++
  entry.lastAttempt = now

  // Block if too many attempts
  if (entry.attempts >= RATE_LIMIT_MAX_ATTEMPTS) {
    entry.blockedUntil = now + RATE_LIMIT_BLOCK_DURATION_MS
    return true
  }

  return false
}

/**
 * Clear rate limit for an IP (call on successful auth)
 */
export function clearRateLimit(ip: string): void {
  rateLimitStore.delete(ip)
}

/**
 * Get rate limit status for debugging
 */
export function getRateLimitStatus(ip: string): RateLimitEntry | null {
  return rateLimitStore.get(ip) || null
}

export const authRateLimitConfig = {
  RATE_LIMIT_MAX_ATTEMPTS,
  RATE_LIMIT_WINDOW_MS,
  RATE_LIMIT_BLOCK_DURATION_MS
} as const

/**
 * Endpoint Rate Limiting Module
 *
 * Provides per-endpoint rate limiting for API requests.
 */

import type { EndpointRateLimitEntry } from './types.js'

// Store: ip:endpoint -> { count, windowStart }
const endpointRateLimitStore = new Map<string, EndpointRateLimitEntry>()

// Default limits per endpoint category (requests per minute)
const ENDPOINT_RATE_LIMITS: Record<string, number> = {
  // Write operations are more restricted
  'POST:/api/terminal/create': 10,
  'POST:/api/pty/spawn': 10,
  'POST:/api/pty/write': 120, // Higher limit for typing
  'POST:/api/tts/speak': 30,
  // Beads operations
  'POST:/projects/beads': 30,
  'PATCH:/projects/beads': 30,
  'DELETE:/projects/beads': 20,
  // Read operations have higher limits
  'GET:/api': 60,
  'GET:/projects': 60,
  // Default fallback
  default: 60
}

const ENDPOINT_RATE_WINDOW_MS = 60 * 1000 // 1 minute window

/**
 * Get the rate limit for an endpoint
 */
function getEndpointRateLimit(method: string, path: string): number {
  // Try exact match first
  const exactKey = `${method}:${path}`
  if (ENDPOINT_RATE_LIMITS[exactKey]) {
    return ENDPOINT_RATE_LIMITS[exactKey]
  }

  // Try prefix matches
  for (const [key, limit] of Object.entries(ENDPOINT_RATE_LIMITS)) {
    if (exactKey.startsWith(key)) {
      return limit
    }
  }

  return ENDPOINT_RATE_LIMITS['default']
}

/**
 * Check if a request is rate limited by endpoint
 * Returns { allowed: boolean, remaining: number, resetIn: number }
 */
export function checkEndpointRateLimit(
  ip: string,
  method: string,
  path: string
): { allowed: boolean; remaining: number; resetIn: number } {
  const now = Date.now()
  const limit = getEndpointRateLimit(method, path)
  const key = `${ip}:${method}:${path}`

  const entry = endpointRateLimitStore.get(key)

  if (!entry) {
    // First request in this window
    endpointRateLimitStore.set(key, { count: 1, windowStart: now })
    return { allowed: true, remaining: limit - 1, resetIn: ENDPOINT_RATE_WINDOW_MS }
  }

  // Check if window has expired
  if (now - entry.windowStart >= ENDPOINT_RATE_WINDOW_MS) {
    // Start new window
    endpointRateLimitStore.set(key, { count: 1, windowStart: now })
    return { allowed: true, remaining: limit - 1, resetIn: ENDPOINT_RATE_WINDOW_MS }
  }

  // Within window - check count
  if (entry.count >= limit) {
    const resetIn = ENDPOINT_RATE_WINDOW_MS - (now - entry.windowStart)
    return { allowed: false, remaining: 0, resetIn }
  }

  // Increment count
  entry.count++
  const remaining = limit - entry.count
  const resetIn = ENDPOINT_RATE_WINDOW_MS - (now - entry.windowStart)
  return { allowed: true, remaining, resetIn }
}

/**
 * Clean up expired endpoint rate limit entries
 * Call periodically to prevent memory growth
 */
export function cleanupEndpointRateLimits(): void {
  const now = Date.now()
  for (const [key, entry] of endpointRateLimitStore.entries()) {
    if (now - entry.windowStart >= ENDPOINT_RATE_WINDOW_MS * 2) {
      endpointRateLimitStore.delete(key)
    }
  }
}

export const endpointRateLimitConfig = {
  ENDPOINT_RATE_LIMITS,
  ENDPOINT_RATE_WINDOW_MS
} as const

/**
 * Token Manager - Token CRUD and encryption
 */

import { randomBytes } from 'crypto'
import { existsSync, readFileSync } from 'fs'
import { app } from 'electron'
import { join } from 'path'
import {
  encryptToken,
  decryptToken,
  writeSecureFile
} from '../mobile-security'
import { log } from './utils'

export function getTokenPath(): string {
  return join(app.getPath('userData'), 'mobile-server-token')
}

export function loadOrCreateToken(): string {
  const tokenPath = getTokenPath()
  try {
    if (existsSync(tokenPath)) {
      const storedData = readFileSync(tokenPath, 'utf-8').trim()

      // Try to decrypt (new encrypted format)
      const decrypted = decryptToken(storedData)
      if (decrypted && decrypted.length === 64) {
        log('Loaded existing encrypted token')
        return decrypted
      }

      // Fallback: check if it's an old unencrypted token (migration path)
      if (storedData.length === 64 && /^[a-f0-9]+$/.test(storedData)) {
        log('Migrating unencrypted token to encrypted storage')
        // Re-save with encryption
        const encrypted = encryptToken(storedData)
        writeSecureFile(tokenPath, encrypted)
        return storedData
      }
    }
  } catch (err) {
    log('Failed to load token, generating new one', { error: String(err) })
  }

  // Generate and save new token with encryption
  const token = randomBytes(32).toString('hex')
  try {
    const encrypted = encryptToken(token)
    writeSecureFile(tokenPath, encrypted)
    log('Generated and saved new encrypted token')
  } catch (err) {
    log('Failed to save token', { error: String(err) })
  }
  return token
}

export function saveToken(token: string): void {
  try {
    const encrypted = encryptToken(token)
    writeSecureFile(getTokenPath(), encrypted)
    log('Saved encrypted token')
  } catch (err) {
    log('Failed to save token', { error: String(err) })
  }
}

export function regenerateToken(): string {
  const token = randomBytes(32).toString('hex')
  try {
    const encrypted = encryptToken(token)
    writeSecureFile(getTokenPath(), encrypted)
    log('Regenerated and saved encrypted token')
  } catch (err) {
    log('Failed to save regenerated token', { error: String(err) })
  }
  return token
}

