/**
 * PTY Routes - /api/pty/* endpoints
 */

import { Express, Request, Response } from 'express'
import { WebSocket } from 'ws'
import { validateProjectPath } from '../../mobile-security'
import { log } from '../utils'
import { LocalPty } from '../types'

export function setupPtyRoutes(
  app: Express,
  getPtyManager: () => any,
  getLocalPtys: () => Map<string, LocalPty>,
  getPtyStreams: () => Map<string, Set<WebSocket>>,
  getPtyDataBuffer: () => Map<string, string[]>,
  broadcastPtyData: (ptyId: string, data: string) => void,
  broadcastPtyExit: (ptyId: string, code: number) => void
): void {
  // Spawn a new PTY
  app.post('/api/pty/spawn', async (req: Request, res: Response) => {
    try {
      const { projectPath, sessionId, model, backend } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'projectPath is required' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      log('PTY spawn request', { projectPath: safeProjectPath, sessionId, model, backend })

      const ptyId = ptyManager.spawn(
        safeProjectPath,
        sessionId,
        undefined, // autoAcceptTools
        undefined, // permissionMode
        model,
        backend
      )

      // Track this PTY for cleanup
      const localPty: LocalPty = {
        ptyId,
        projectPath: safeProjectPath,
        dataCallbacks: new Set(),
        exitCallbacks: new Set()
      }
      getLocalPtys().set(ptyId, localPty)

      // Set up data forwarding to WebSocket streams
      ptyManager.onData(ptyId, (data: string) => {
        broadcastPtyData(ptyId, data)
      })

      // Set up exit handler
      ptyManager.onExit(ptyId, (code: number) => {
        log('PTY exited', { ptyId, code })
        broadcastPtyExit(ptyId, code)
        getLocalPtys().delete(ptyId)
        getPtyStreams().delete(ptyId)
        getPtyDataBuffer().delete(ptyId)
      })

      log('PTY spawned', { ptyId, projectPath })
      res.json({ ptyId })
    } catch (error) {
      log('PTY spawn error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Write data to PTY
  app.post('/api/pty/:id/write', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { data } = req.body

      if (!data || typeof data !== 'string') {
        return res.status(400).json({ error: 'data is required and must be a string' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.write(id, data)
      log('PTY write', { ptyId: id, dataLength: data.length })
      res.json({ success: true })
    } catch (error) {
      log('PTY write error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Resize PTY
  app.post('/api/pty/:id/resize', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { cols, rows } = req.body

      if (typeof cols !== 'number' || typeof rows !== 'number') {
        return res.status(400).json({ error: 'cols and rows are required and must be numbers' })
      }

      if (cols < 1 || rows < 1 || cols > 500 || rows > 500) {
        return res.status(400).json({ error: 'cols and rows must be between 1 and 500' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.resize(id, cols, rows)
      log('PTY resize', { ptyId: id, cols, rows })
      res.json({ success: true })
    } catch (error) {
      log('PTY resize error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Kill PTY
  app.delete('/api/pty/:id', (req: Request, res: Response) => {
    try {
      const { id } = req.params

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.kill(id)
      getLocalPtys().delete(id)

      // Close any WebSocket streams for this PTY
      const streams = getPtyStreams().get(id)
      if (streams) {
        streams.forEach(ws => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.close(1000, 'PTY killed')
          }
        })
        getPtyStreams().delete(id)
      }

      log('PTY killed', { ptyId: id })
      res.json({ success: true })
    } catch (error) {
      log('PTY kill error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

/**
 * Mobile API Server - Express Application
 *
 * Main server setup that exposes desktop IPC functionality as HTTP/WebSocket endpoints.
 * Enables mobile app communication with the Claude Terminal desktop application.
 */

import express, { Express, Request, Response, NextFunction } from 'express'
import * as http from 'http'
import cors from 'cors'
import {
  MobileApiServerConfig,
  DEFAULT_SERVER_CONFIG,
  ApiResponse
} from './types'
import {
  authMiddleware,
  generatePrimaryToken,
  getPrimaryToken,
  getConnectionInfo,
  cleanupExpiredTokens
} from './auth'
import { createApiRouter } from './routes'
import { WebSocketHandler } from './ws-handler'

// =============================================================================
// Server State
// =============================================================================

let serverInstance: http.Server | null = null
let wsHandler: WebSocketHandler | null = null
let cleanupInterval: NodeJS.Timeout | null = null

// =============================================================================
// Service Registrations (IPC Handler Adapters)
// =============================================================================

/**
 * Service interfaces that bridge IPC handlers to HTTP endpoints
 * These are set by the main process to provide access to existing functionality
 */
export interface ServerServices {
  // Workspace/Project management
  getWorkspace: () => Promise<any>
  saveWorkspace: (workspace: any) => Promise<void>

  // Settings
  getSettings: () => Promise<any>
  saveSettings: (settings: any) => Promise<void>

  // Sessions
  discoverSessions: (projectPath: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => Promise<any[]>

  // PTY management
  spawnPty: (cwd: string, sessionId?: string, model?: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => Promise<string>
  writePty: (id: string, data: string) => void
  resizePty: (id: string, cols: number, rows: number) => void
  killPty: (id: string) => void
  onPtyData: (id: string, callback: (data: string) => void) => () => void
  onPtyExit: (id: string, callback: (code: number) => void) => () => void

  // Beads task management
  beadsCheck: (cwd: string) => Promise<any>
  beadsInit: (cwd: string) => Promise<any>
  beadsList: (cwd: string) => Promise<any>
  beadsShow: (cwd: string, taskId: string) => Promise<any>
  beadsCreate: (cwd: string, title: string, description?: string, priority?: number, type?: string, labels?: string) => Promise<any>
  beadsComplete: (cwd: string, taskId: string) => Promise<any>
  beadsDelete: (cwd: string, taskId: string) => Promise<any>
  beadsStart: (cwd: string, taskId: string) => Promise<any>
  beadsUpdate: (cwd: string, taskId: string, status?: string, title?: string, description?: string, priority?: number) => Promise<any>

  // GSD progress
  gsdProjectCheck: (cwd: string) => Promise<any>
  gsdGetProgress: (cwd: string) => Promise<any>

  // Voice (TTS)
  voiceSpeak: (text: string) => Promise<any>
  voiceStopSpeaking: () => Promise<any>
  voiceGetSettings: () => Promise<any>

  // CLI checks
  claudeCheck: () => Promise<any>
  geminiCheck: () => Promise<any>
  codexCheck: () => Promise<any>
  opencodeCheck: () => Promise<any>
  aiderCheck: () => Promise<any>
}

let services: Partial<ServerServices> = {}

/**
 * Register services that provide IPC handler functionality
 */
export function registerServices(newServices: Partial<ServerServices>): void {
  services = { ...services, ...newServices }
}

/**
 * Get registered services
 */
export function getServices(): Partial<ServerServices> {
  return services
}

// =============================================================================
// Express App Factory
// =============================================================================

/**
 * Create and configure the Express application
 */
export function createApp(config: MobileApiServerConfig = DEFAULT_SERVER_CONFIG): Express {
  const app = express()

  // ==========================================================================
  // Middleware Stack
  // ==========================================================================

  // JSON body parsing with size limit
  app.use(express.json({ limit: '100kb' }))

  // CORS configuration
  if (config.enableCors) {
    app.use(cors({
      origin: config.corsOrigins || '*',
      methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
      allowedHeaders: ['Content-Type', 'Authorization'],
      credentials: true
    }))
  }

  // Request logging (development)
  app.use((req: Request, _res: Response, next: NextFunction) => {
    console.log(`[Mobile API] ${req.method} ${req.path}`)
    next()
  })

  // ==========================================================================
  // Health Check (unauthenticated)
  // ==========================================================================

  app.get('/health', (_req: Request, res: Response) => {
    const response: ApiResponse<{ status: string; uptime: number }> = {
      success: true,
      data: {
        status: 'healthy',
        uptime: process.uptime()
      },
      timestamp: Date.now()
    }
    res.json(response)
  })

  // ==========================================================================
  // Connection Info (unauthenticated - for initial pairing)
  // ==========================================================================

  app.get('/connect', (_req: Request, res: Response) => {
    const token = getPrimaryToken()
    if (!token) {
      res.status(503).json({
        success: false,
        error: 'Server not fully initialized',
        timestamp: Date.now()
      })
      return
    }

    // Return connection info for QR code
    const info = getConnectionInfo(config.host, config.port)
    res.json({
      success: true,
      data: {
        version: 1,
        wsEndpoint: `/ws`,
        apiEndpoint: `/api`,
        tokenHint: info.token.slice(0, 8) + '...' // Partial token for verification
      },
      timestamp: Date.now()
    })
  })

  // ==========================================================================
  // API Routes (authenticated)
  // ==========================================================================

  // Apply auth middleware to all /api routes
  app.use('/api', authMiddleware as any)

  // Mount the API router
  app.use('/api', createApiRouter())

  // ==========================================================================
  // Error Handling
  // ==========================================================================

  // 404 handler
  app.use((_req: Request, res: Response) => {
    res.status(404).json({
      success: false,
      error: 'Endpoint not found',
      timestamp: Date.now()
    })
  })

  // Global error handler
  app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
    console.error('[Mobile API] Error:', err)
    res.status(500).json({
      success: false,
      error: process.env.NODE_ENV === 'development' ? err.message : 'Internal server error',
      timestamp: Date.now()
    })
  })

  return app
}

// =============================================================================
// Server Lifecycle
// =============================================================================

/**
 * Start the mobile API server
 */
export function startServer(
  config: Partial<MobileApiServerConfig> = {}
): Promise<{ server: http.Server; wsHandler: WebSocketHandler; token: string }> {
  return new Promise((resolve, reject) => {
    const fullConfig: MobileApiServerConfig = { ...DEFAULT_SERVER_CONFIG, ...config }

    // Stop existing server if running
    if (serverInstance) {
      stopServer()
    }

    // Generate primary auth token
    const token = generatePrimaryToken()
    console.log('[Mobile API] Generated auth token:', token.token.slice(0, 8) + '...')

    // Create Express app
    const app = createApp(fullConfig)

    // Create HTTP server
    serverInstance = http.createServer(app)

    // Set up WebSocket handler if enabled
    if (fullConfig.enableWebSocket) {
      wsHandler = new WebSocketHandler(serverInstance, fullConfig.maxConnections)
    }

    // Start periodic cleanup of expired tokens
    cleanupInterval = setInterval(() => {
      const cleaned = cleanupExpiredTokens()
      if (cleaned > 0) {
        console.log(`[Mobile API] Cleaned up ${cleaned} expired tokens`)
      }
    }, 60000) // Every minute

    // Start listening
    serverInstance.listen(fullConfig.port, fullConfig.host, () => {
      console.log(`[Mobile API] Server started on ${fullConfig.host}:${fullConfig.port}`)
      console.log(`[Mobile API] WebSocket endpoint: ws://${fullConfig.host}:${fullConfig.port}/ws`)

      resolve({
        server: serverInstance!,
        wsHandler: wsHandler!,
        token: token.token
      })
    })

    serverInstance.on('error', (error: NodeJS.ErrnoException) => {
      console.error('[Mobile API] Server error:', error)
      if (error.code === 'EADDRINUSE') {
        reject(new Error(`Port ${fullConfig.port} is already in use`))
      } else {
        reject(error)
      }
    })
  })
}

/**
 * Stop the mobile API server
 */
export function stopServer(): Promise<void> {
  return new Promise((resolve) => {
    // Stop cleanup interval
    if (cleanupInterval) {
      clearInterval(cleanupInterval)
      cleanupInterval = null
    }

    // Close WebSocket handler
    if (wsHandler) {
      wsHandler.closeAll()
      wsHandler = null
    }

    // Close HTTP server
    if (serverInstance) {
      serverInstance.close(() => {
        console.log('[Mobile API] Server stopped')
        serverInstance = null
        resolve()
      })
    } else {
      resolve()
    }
  })
}

/**
 * Check if server is running
 */
export function isServerRunning(): boolean {
  return serverInstance !== null && serverInstance.listening
}

/**
 * Get the WebSocket handler instance
 */
export function getWsHandler(): WebSocketHandler | null {
  return wsHandler
}

/**
 * Get server information
 */
export function getServerInfo(): {
  running: boolean
  port?: number
  host?: string
  token?: string
  connections?: number
} {
  if (!serverInstance || !serverInstance.listening) {
    return { running: false }
  }

  const address = serverInstance.address()
  const token = getPrimaryToken()

  return {
    running: true,
    port: typeof address === 'object' && address ? address.port : undefined,
    host: typeof address === 'object' && address ? address.address : undefined,
    token: token?.token,
    connections: wsHandler?.getConnectionCount() ?? 0
  }
}

import { BrowserWindow } from 'electron'
import { ApiServerManager, PromptResult } from '../api-server.js'
import { SessionStore } from '../session-store.js'
import { PtyManager } from '../pty-manager.js'
import { API_DUPLICATE_WINDOW_MS, API_SESSION_TIMEOUT_MS } from '../../constants.js'

export interface PendingApiPrompt {
  prompt: string
  resolve: (result: PromptResult) => void
  autoClose: boolean
  model?: string
}

export const pendingApiPrompts = new Map<string, PendingApiPrompt>()
export const autoCloseSessions = new Set<string>()

const recentApiPrompts = new Map<string, { prompt: string; timestamp: number }>()

function cleanupStaleApiPrompts(now: number): void {
  for (const [key, value] of recentApiPrompts) {
    if (now - value.timestamp >= API_DUPLICATE_WINDOW_MS) {
      recentApiPrompts.delete(key)
    }
  }
}

export function setupApiPromptHandler(
  apiServerManager: ApiServerManager,
  sessionStore: SessionStore,
  ptyManager: PtyManager,
  ptyToProject: Map<string, string>,
  getMainWindow: () => BrowserWindow | null
): void {
  apiServerManager.setSessionModeGetter((projectPath) => {
    const workspace = sessionStore.getWorkspace()
    const project = workspace.projects.find(p => p.path === projectPath)
    return project?.apiSessionMode || 'existing'
  })

  apiServerManager.setPromptHandler(async (projectPath, prompt, sessionMode): Promise<PromptResult> => {
    const now = Date.now()

    // Clean up stale entries to prevent memory growth
    cleanupStaleApiPrompts(now)

    const recent = recentApiPrompts.get(projectPath)
    if (recent && recent.prompt === prompt && now - recent.timestamp < API_DUPLICATE_WINDOW_MS) {
      console.log('API: Ignoring duplicate prompt for', projectPath)
      return { success: true, message: 'Duplicate prompt ignored' }
    }
    recentApiPrompts.set(projectPath, { prompt, timestamp: now })

    if (sessionMode === 'existing') {
      for (const [ptyId, path] of ptyToProject) {
        if (path === projectPath) {
          ptyManager.write(ptyId, prompt)
          setTimeout(() => ptyManager.write(ptyId, '\r'), 300)
          return { success: true, message: 'Prompt sent to existing terminal' }
        }
      }
      return { success: false, error: 'No active terminal for this project' }
    }

    const workspace = sessionStore.getWorkspace()
    const project = workspace.projects.find(p => p.path === projectPath)
    const model = project?.apiModel
    const mainWindow = getMainWindow()

    return new Promise((resolve) => {
      pendingApiPrompts.set(projectPath, { prompt, resolve, autoClose: sessionMode === 'new-close', model })
      mainWindow?.webContents.send('api:open-session', { projectPath, autoClose: sessionMode === 'new-close', model })
      setTimeout(() => {
        const pending = pendingApiPrompts.get(projectPath)
        if (pending && pending.resolve === resolve) {
          pendingApiPrompts.delete(projectPath)
          resolve({ success: false, error: 'Timeout waiting for session to be created' })
        }
      }, API_SESSION_TIMEOUT_MS)
    })
  })
}

