/**
 * HTTP/WebSocket Backend Implementation
 *
 * This module implements the Api interface using HTTP requests and WebSocket
 * connections to communicate with the mobile server running on a desktop host.
 */

import {
  Api,
  ConnectionState,
  Settings,
  Workspace,
  Session,
  PtyDataCallback,
  PtyExitCallback,
  PtyRecreatedCallback,
  ApiOpenSessionCallback,
  Unsubscribe,
  BackendId
} from '../types'
import { HttpBackendConfig } from './types'
import { DEFAULT_PORT } from './constants'
import { isLocalNetwork } from './helpers'
import { ConnectionManager } from './connection'
import { PtyWebSocketManager } from './pty-websocket'
import { PtyApi } from './pty-api'
import { WorkspaceApi } from './workspace-api'

export class HttpBackend implements Api {
  voiceGetInstalled?: () => Promise<
    Array<{
      key: string
      displayName: string
      source: 'builtin' | 'downloaded' | 'custom'
      quality?: string
      language?: string
    }>
  >
  xttsGetVoices?: () => Promise<
    Array<{ id: string; name: string; language: string; createdAt: number }>
  >
  voiceGetSettings?: () => Promise<{ ttsVoice?: string; ttsEngine?: string }>
  apiStart?: (
    projectPath: string,
    port: number
  ) => Promise<{ success: boolean; error?: string }>
  apiStop?: (projectPath: string) => Promise<{ success: boolean }>

  private host: string
  private port: number
  private connection: ConnectionManager
  private wsManager: PtyWebSocketManager
  private ptyApi: PtyApi
  private workspaceApi: WorkspaceApi

  constructor(config: HttpBackendConfig) {
    // Validate port to prevent requests to invalid addresses like localhost:1
    if (
      !config.port ||
      config.port < 1 ||
      config.port > 65535 ||
      !Number.isInteger(config.port)
    ) {
      console.error('[HttpBackend] Invalid port:', config.port, '- using default', DEFAULT_PORT)
      config.port = DEFAULT_PORT
    }
    if (config.port < 1024) {
      console.warn(
        '[HttpBackend] Port',
        config.port,
        'is a privileged port (< 1024), this may fail'
      )
    }

    this.host = config.host
    this.port = config.port

    // Determine protocol based on whether host is local
    const httpProtocol = isLocalNetwork(config.host) ? 'http' : 'https'
    const wsProtocol = isLocalNetwork(config.host) ? 'ws' : 'wss'

    const baseUrl = `${httpProtocol}://${config.host}:${config.port}`
    const wsBaseUrl = `${wsProtocol}://${config.host}:${config.port}`

    console.log('[HttpBackend] Initialized with baseUrl:', baseUrl)

    // Initialize managers
    this.connection = new ConnectionManager(baseUrl, config.token)
    this.wsManager = new PtyWebSocketManager(wsBaseUrl, config.token)
    this.ptyApi = new PtyApi(this.connection, this.wsManager)
    this.workspaceApi = new WorkspaceApi(this.connection)
  }

  // Connection State Management

  getConnectionState(): ConnectionState {
    return this.connection.getConnectionState()
  }

  getConnectionError(): string | null {
    return this.connection.getConnectionError()
  }

  onConnectionStateChange(callback: (state: ConnectionState) => void): Unsubscribe {
    return this.connection.onConnectionStateChange(callback)
  }

  // PTY Management

  spawnPty(cwd: string, sessionId?: string, model?: string, backend?: BackendId): Promise<string> {
    return this.ptyApi.spawnPty(cwd, sessionId, model, backend)
  }

  killPty(id: string): void {
    this.ptyApi.killPty(id)
  }

  writePty(id: string, data: string): void {
    this.ptyApi.writePty(id, data)
  }

  resizePty(id: string, cols: number, rows: number): void {
    this.ptyApi.resizePty(id, cols, rows)
  }

  onPtyData(id: string, callback: PtyDataCallback): Unsubscribe {
    return this.ptyApi.onPtyData(id, callback)
  }

  onPtyExit(id: string, callback: PtyExitCallback): Unsubscribe {
    return this.ptyApi.onPtyExit(id, callback)
  }

  onPtyRecreated(callback: PtyRecreatedCallback): Unsubscribe {
    return this.ptyApi.onPtyRecreated(callback)
  }

  // Session Management

  discoverSessions(projectPath: string, backend?: BackendId): Promise<Session[]> {
    return this.workspaceApi.discoverSessions(projectPath, backend)
  }

  // Workspace Management

  getWorkspace(): Promise<Workspace> {
    return this.workspaceApi.getWorkspace()
  }

  saveWorkspace(workspace: Workspace): Promise<void> {
    return this.workspaceApi.saveWorkspace(workspace)
  }

  // Settings Management

  getSettings(): Promise<Settings> {
    return this.workspaceApi.getSettings()
  }

  saveSettings(settings: Settings): Promise<void> {
    return this.workspaceApi.saveSettings(settings)
  }

  // Project Management

  addProject(): Promise<string | null> {
    return this.workspaceApi.addProject()
  }

  addProjectsFromParent(): Promise<Array<{ path: string; name: string }> | null> {
    return this.workspaceApi.addProjectsFromParent()
  }

  // TTS

  ttsInstallInstructions(projectPath: string): Promise<{ success: boolean }> {
    return this.workspaceApi.ttsInstallInstructions(projectPath)
  }

  ttsSpeak(text: string): Promise<{ success: boolean; audioData?: string; error?: string }> {
    return this.workspaceApi.ttsSpeak(text)
  }

  ttsStop(): Promise<{ success: boolean }> {
    return this.workspaceApi.ttsStop()
  }

  // Events

  onApiOpenSession(callback: ApiOpenSessionCallback): Unsubscribe {
    return this.workspaceApi.onApiOpenSession(callback)
  }

  // Connection Management

  getConnectionInfo(): { host: string; port: number; token: string } {
    return {
      host: this.host,
      port: this.port,
      token: this.connection.getToken()
    }
  }

  async testConnection(): Promise<{ success: boolean; error?: string }> {
    try {
      this.connection.setConnectionState('connecting')
      const response = await fetch(`${this.connection.getBaseUrl()}/health`)

      if (!response.ok) {
        this.connection.setConnectionState('error', `HTTP ${response.status}`)
        return { success: false, error: `HTTP ${response.status}` }
      }

      await response.json()
      this.connection.setConnectionState('connected')
      return { success: true }
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Connection failed'
      this.connection.setConnectionState('error', message)
      return { success: false, error: message }
    }
  }

  disconnect(): void {
    this.wsManager.disconnectAll()
    this.connection.setConnectionState('disconnected')
  }
}

/**
 * Mobile Security Types
 *
 * Shared type definitions for the mobile security module.
 */

export type IpClass = 'localhost' | 'local_network' | 'public'

export interface RateLimitEntry {
  attempts: number
  lastAttempt: number
  blockedUntil: number | null
}

export interface NonceEntry {
  nonce: string
  createdAt: number
  expiresAt: number
  used: boolean
}

export interface EndpointRateLimitEntry {
  count: number
  windowStart: number
}

export interface PathValidationResult {
  valid: boolean
  error?: string
  normalizedPath?: string
}

export interface PathValidationOptions {
  mustExist?: boolean
  mustBeDirectory?: boolean
  allowedBasePaths?: string[]
}

/**
 * Mobile Server Security Module
 *
 * Provides security utilities for the mobile server:
 * - IP classification (localhost, local_network, public)
 * - Rate limiting for failed auth attempts
 * - Server fingerprint generation (persistent identity)
 * - One-time handshake nonces for QR code security
 * - Token encryption for secure storage
 * - Path validation and sanitization
 */

// Types
export type { IpClass, RateLimitEntry, NonceEntry, PathValidationResult, PathValidationOptions } from './types.js'

// IP Classification
export { classifyIp, getClientIp } from './ip-classification.js'

// Auth Rate Limiting
export { checkRateLimit, recordFailedAuth, clearRateLimit, getRateLimitStatus, authRateLimitConfig } from './auth-rate-limit.js'

// Endpoint Rate Limiting
export { checkEndpointRateLimit, cleanupEndpointRateLimits, endpointRateLimitConfig } from './endpoint-rate-limit.js'

// Server Fingerprint (legacy - use certificate fingerprint for new code)
export { getOrCreateFingerprint, getFormattedFingerprint } from './fingerprint.js'

// TLS Certificate (for HTTPS with certificate pinning)
export {
  getOrCreateCertificate,
  getCertificateFingerprint,
  getFormattedCertFingerprint,
  getTlsOptions,
  regenerateCertificate,
  certificateExists
} from './certificate.js'
export type { CertificateData } from './certificate.js'

// Nonce Management
export { startNonceCleanup, stopNonceCleanup, createNonce, verifyNonce, getNonceInfo, nonceConfig } from './nonces.js'

// Token Encryption
export { encryptToken, decryptToken, writeSecureFile } from './encryption.js'

// Path Validation
export { validatePath, validateProjectPath, validateFilePath, validateDirectoryPath } from './path-validation.js'

// Combined security config for backwards compatibility
export const securityConfig = {
  RATE_LIMIT_MAX_ATTEMPTS: 5,
  RATE_LIMIT_WINDOW_MS: 15 * 60 * 1000,
  RATE_LIMIT_BLOCK_DURATION_MS: 15 * 60 * 1000,
  NONCE_EXPIRY_MS: 5 * 60 * 1000
} as const

/**
 * Nonce Management Module
 *
 * Manages one-time handshake nonces for QR code security.
 */

import { randomBytes } from 'crypto'
import type { NonceEntry } from './types.js'

const NONCE_EXPIRY_MS = 5 * 60 * 1000 // 5 minutes
const NONCE_CLEANUP_INTERVAL_MS = 60 * 1000 // 1 minute

const nonceStore = new Map<string, NonceEntry>()
let cleanupInterval: ReturnType<typeof setInterval> | null = null

/**
 * Start the nonce cleanup interval
 */
export function startNonceCleanup(): void {
  if (cleanupInterval) return

  cleanupInterval = setInterval(() => {
    const now = Date.now()
    for (const [nonce, entry] of nonceStore.entries()) {
      if (entry.expiresAt < now || entry.used) {
        nonceStore.delete(nonce)
      }
    }
  }, NONCE_CLEANUP_INTERVAL_MS)
}

/**
 * Stop the nonce cleanup interval
 */
export function stopNonceCleanup(): void {
  if (cleanupInterval) {
    clearInterval(cleanupInterval)
    cleanupInterval = null
  }
}

/**
 * Create a new one-time nonce for QR code handshake
 */
export function createNonce(): { nonce: string; expiresAt: number } {
  const nonce = randomBytes(16).toString('hex')
  const now = Date.now()
  const expiresAt = now + NONCE_EXPIRY_MS

  nonceStore.set(nonce, {
    nonce,
    createdAt: now,
    expiresAt,
    used: false
  })

  return { nonce, expiresAt }
}

/**
 * Verify and consume a nonce
 * Returns true if nonce is valid and not yet used
 */
export function verifyNonce(nonce: string): boolean {
  const entry = nonceStore.get(nonce)

  if (!entry) {
    return false
  }

  const now = Date.now()

  // Check if expired
  if (entry.expiresAt < now) {
    nonceStore.delete(nonce)
    return false
  }

  // Check if already used
  if (entry.used) {
    return false
  }

  // Mark as used
  entry.used = true

  return true
}

/**
 * Get nonce info without consuming it (for debugging)
 */
export function getNonceInfo(nonce: string): NonceEntry | null {
  return nonceStore.get(nonce) || null
}

export const nonceConfig = {
  NONCE_EXPIRY_MS,
  NONCE_CLEANUP_INTERVAL_MS
} as const

import * as http from 'http'
import type { PtyManager } from './pty-manager.js'

const ORCHESTRATOR_PORT = 19836

export class OrchestratorApi {
  private server: http.Server | null = null
  private ptyManager: PtyManager
  private ptyToProject: Map<string, string>

  constructor(ptyManager: PtyManager, ptyToProject: Map<string, string>) {
    this.ptyManager = ptyManager
    this.ptyToProject = ptyToProject
  }

  start(): void {
    if (this.server) return

    this.server = http.createServer((req, res) => {
      res.setHeader('Content-Type', 'application/json')

      // Only allow localhost
      const remote = req.socket.remoteAddress
      if (remote !== '127.0.0.1' && remote !== '::1' && remote !== '::ffff:127.0.0.1') {
        res.writeHead(403)
        res.end(JSON.stringify({ error: 'Forbidden' }))
        return
      }

      const url = new URL(req.url || '/', `http://localhost:${ORCHESTRATOR_PORT}`)
      const path = url.pathname

      // Match: /sessions/:id/output or /sessions/:id/input
      const sessionMatch = path.match(/^\/sessions\/([^/]+)\/(output|input)$/)

      if (req.method === 'GET' && path === '/sessions') {
        this.handleListSessions(res)
      } else if (req.method === 'GET' && sessionMatch?.[2] === 'output') {
        const maxLines = parseInt(url.searchParams.get('lines') || '50', 10)
        this.handleReadOutput(sessionMatch[1], maxLines, res)
      } else if (req.method === 'POST' && sessionMatch?.[2] === 'input') {
        this.handleSendInput(sessionMatch[1], req, res)
      } else {
        res.writeHead(404)
        res.end(JSON.stringify({ error: 'Not found' }))
      }
    })

    this.server.listen(ORCHESTRATOR_PORT, '127.0.0.1', () => {
      console.log(`[Orchestrator] API server started on port ${ORCHESTRATOR_PORT}`)
    })

    this.server.on('error', (e: NodeJS.ErrnoException) => {
      if (e.code === 'EADDRINUSE') {
        console.warn(`[Orchestrator] Port ${ORCHESTRATOR_PORT} in use, trying ${ORCHESTRATOR_PORT + 1}`)
        this.server?.listen(ORCHESTRATOR_PORT + 1, '127.0.0.1')
      } else {
        console.error('[Orchestrator] API server error:', e.message)
      }
    })
  }

  stop(): void {
    this.server?.close()
    this.server = null
  }

  private handleListSessions(res: http.ServerResponse): void {
    const sessions = this.ptyManager.listSessions()
    // Enrich with project path from ptyToProject map
    const enriched = sessions.map(s => ({
      ...s,
      projectPath: this.ptyToProject.get(s.id) || s.cwd,
      projectName: (this.ptyToProject.get(s.id) || s.cwd).split('/').pop() || 'unknown',
    }))
    res.writeHead(200)
    res.end(JSON.stringify({ sessions: enriched }))
  }

  private handleReadOutput(id: string, maxLines: number, res: http.ServerResponse): void {
    const lines = this.ptyManager.readOutput(id, maxLines)
    if (lines === null) {
      res.writeHead(404)
      res.end(JSON.stringify({ error: 'Session not found' }))
      return
    }
    res.writeHead(200)
    res.end(JSON.stringify({ lines }))
  }

  private handleSendInput(id: string, req: http.IncomingMessage, res: http.ServerResponse): void {
    let body = ''
    req.on('data', chunk => {
      body += chunk
      if (body.length > 10240) {
        res.writeHead(413)
        res.end(JSON.stringify({ error: 'Input too large' }))
        req.destroy()
      }
    })
    req.on('end', () => {
      try {
        const data = JSON.parse(body)
        const input = data.input || data.text || data.message || ''
        if (!input) {
          res.writeHead(400)
          res.end(JSON.stringify({ error: 'No input provided' }))
          return
        }

        const proc = this.ptyManager.getProcess(id)
        if (!proc) {
          res.writeHead(404)
          res.end(JSON.stringify({ error: 'Session not found' }))
          return
        }

        // Write input followed by carriage return (simulates pressing Enter in terminal)
        this.ptyManager.write(id, input + '\r')
        res.writeHead(200)
        res.end(JSON.stringify({ success: true, message: `Input sent to session ${id}` }))
      } catch {
        res.writeHead(400)
        res.end(JSON.stringify({ error: 'Invalid JSON' }))
      }
    })
  }
}

export { ORCHESTRATOR_PORT }

