/**
 * Authentication Rate Limiting Module
 *
 * Provides rate limiting for failed authentication attempts.
 */

import type { RateLimitEntry } from './types.js'

// Constants
const RATE_LIMIT_MAX_ATTEMPTS = 5
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000 // 15 minutes
const RATE_LIMIT_BLOCK_DURATION_MS = 15 * 60 * 1000 // 15 minutes

const rateLimitStore = new Map<string, RateLimitEntry>()

/**
 * Check if an IP is rate limited
 * Returns { allowed: boolean, retryAfter?: number }
 */
export function checkRateLimit(ip: string): { allowed: boolean; retryAfter?: number } {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    return { allowed: true }
  }

  // Check if currently blocked
  if (entry.blockedUntil && entry.blockedUntil > now) {
    return {
      allowed: false,
      retryAfter: Math.ceil((entry.blockedUntil - now) / 1000)
    }
  }

  // Check if window has expired - reset if so
  if (now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.delete(ip)
    return { allowed: true }
  }

  return { allowed: true }
}

/**
 * Record a failed authentication attempt for an IP
 * Returns true if the IP is now blocked
 */
export function recordFailedAuth(ip: string): boolean {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Reset if window has expired
  if (now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Increment attempts
  entry.attempts++
  entry.lastAttempt = now

  // Block if too many attempts
  if (entry.attempts >= RATE_LIMIT_MAX_ATTEMPTS) {
    entry.blockedUntil = now + RATE_LIMIT_BLOCK_DURATION_MS
    return true
  }

  return false
}

/**
 * Clear rate limit for an IP (call on successful auth)
 */
export function clearRateLimit(ip: string): void {
  rateLimitStore.delete(ip)
}

/**
 * Get rate limit status for debugging
 */
export function getRateLimitStatus(ip: string): RateLimitEntry | null {
  return rateLimitStore.get(ip) || null
}

export const authRateLimitConfig = {
  RATE_LIMIT_MAX_ATTEMPTS,
  RATE_LIMIT_WINDOW_MS,
  RATE_LIMIT_BLOCK_DURATION_MS
} as const

/**
 * Endpoint Rate Limiting Module
 *
 * Provides per-endpoint rate limiting for API requests.
 */

import type { EndpointRateLimitEntry } from './types.js'

// Store: ip:endpoint -> { count, windowStart }
const endpointRateLimitStore = new Map<string, EndpointRateLimitEntry>()

// Default limits per endpoint category (requests per minute)
const ENDPOINT_RATE_LIMITS: Record<string, number> = {
  // Write operations are more restricted
  'POST:/api/terminal/create': 10,
  'POST:/api/pty/spawn': 10,
  'POST:/api/pty/write': 120, // Higher limit for typing
  'POST:/api/tts/speak': 30,
  // Beads operations
  'POST:/projects/beads': 30,
  'PATCH:/projects/beads': 30,
  'DELETE:/projects/beads': 20,
  // Read operations have higher limits
  'GET:/api': 60,
  'GET:/projects': 60,
  // Default fallback
  default: 60
}

const ENDPOINT_RATE_WINDOW_MS = 60 * 1000 // 1 minute window

/**
 * Get the rate limit for an endpoint
 */
function getEndpointRateLimit(method: string, path: string): number {
  // Try exact match first
  const exactKey = `${method}:${path}`
  if (ENDPOINT_RATE_LIMITS[exactKey]) {
    return ENDPOINT_RATE_LIMITS[exactKey]
  }

  // Try prefix matches
  for (const [key, limit] of Object.entries(ENDPOINT_RATE_LIMITS)) {
    if (exactKey.startsWith(key)) {
      return limit
    }
  }

  return ENDPOINT_RATE_LIMITS['default']
}

/**
 * Check if a request is rate limited by endpoint
 * Returns { allowed: boolean, remaining: number, resetIn: number }
 */
export function checkEndpointRateLimit(
  ip: string,
  method: string,
  path: string
): { allowed: boolean; remaining: number; resetIn: number } {
  const now = Date.now()
  const limit = getEndpointRateLimit(method, path)
  const key = `${ip}:${method}:${path}`

  const entry = endpointRateLimitStore.get(key)

  if (!entry) {
    // First request in this window
    endpointRateLimitStore.set(key, { count: 1, windowStart: now })
    return { allowed: true, remaining: limit - 1, resetIn: ENDPOINT_RATE_WINDOW_MS }
  }

  // Check if window has expired
  if (now - entry.windowStart >= ENDPOINT_RATE_WINDOW_MS) {
    // Start new window
    endpointRateLimitStore.set(key, { count: 1, windowStart: now })
    return { allowed: true, remaining: limit - 1, resetIn: ENDPOINT_RATE_WINDOW_MS }
  }

  // Within window - check count
  if (entry.count >= limit) {
    const resetIn = ENDPOINT_RATE_WINDOW_MS - (now - entry.windowStart)
    return { allowed: false, remaining: 0, resetIn }
  }

  // Increment count
  entry.count++
  const remaining = limit - entry.count
  const resetIn = ENDPOINT_RATE_WINDOW_MS - (now - entry.windowStart)
  return { allowed: true, remaining, resetIn }
}

/**
 * Clean up expired endpoint rate limit entries
 * Call periodically to prevent memory growth
 */
export function cleanupEndpointRateLimits(): void {
  const now = Date.now()
  for (const [key, entry] of endpointRateLimitStore.entries()) {
    if (now - entry.windowStart >= ENDPOINT_RATE_WINDOW_MS * 2) {
      endpointRateLimitStore.delete(key)
    }
  }
}

export const endpointRateLimitConfig = {
  ENDPOINT_RATE_LIMITS,
  ENDPOINT_RATE_WINDOW_MS
} as const

import * as http from 'http'

interface ApiServer {
  server: http.Server
  port: number
  projectPath: string
}

export type SessionMode = 'existing' | 'new-keep' | 'new-close'

export interface PromptResult {
  success: boolean
  message?: string
  error?: string
  sessionCreated?: boolean
}

type PromptHandler = (projectPath: string, prompt: string, sessionMode: SessionMode) => Promise<PromptResult>

type SessionModeGetter = (projectPath: string) => SessionMode

// Rate limiting configuration
const RATE_LIMIT_MAX_REQUESTS = 10
const RATE_LIMIT_WINDOW_MS = 60000 // 1 minute

// Maximum allowed request body size (100KB) to prevent DoS attacks
const MAX_BODY_SIZE = 100 * 1024

interface RateLimitEntry {
  count: number
  windowStart: number
}

export class ApiServerManager {
  private servers: Map<string, ApiServer> = new Map() // projectPath -> server
  private promptHandler: PromptHandler | null = null
  private sessionModeGetter: SessionModeGetter | null = null
  private rateLimitMap: Map<string, RateLimitEntry> = new Map() // IP -> rate limit info

  setPromptHandler(handler: PromptHandler) {
    this.promptHandler = handler
  }

  setSessionModeGetter(getter: SessionModeGetter) {
    this.sessionModeGetter = getter
  }

  private checkRateLimit(ip: string): boolean {
    const now = Date.now()
    const entry = this.rateLimitMap.get(ip)

    if (!entry || now - entry.windowStart >= RATE_LIMIT_WINDOW_MS) {
      // Start a new window
      this.rateLimitMap.set(ip, { count: 1, windowStart: now })
      return true
    }

    if (entry.count >= RATE_LIMIT_MAX_REQUESTS) {
      return false // Rate limited
    }

    entry.count++
    return true
  }

  private cleanupRateLimitMap(): void {
    const now = Date.now()
    for (const [ip, entry] of this.rateLimitMap) {
      if (now - entry.windowStart >= RATE_LIMIT_WINDOW_MS) {
        this.rateLimitMap.delete(ip)
      }
    }
  }

  start(projectPath: string, port: number): { success: boolean; error?: string } {
    // Validate port is a number and within valid range (excluding privileged ports)
    if (!Number.isInteger(port) || port < 1024 || port > 65535) {
      return { success: false, error: 'Invalid port: must be an integer between 1024 and 65535' }
    }

    // Stop existing server for this project if any
    this.stop(projectPath)

    // Check if port is already in use by another project
    for (const [path, server] of this.servers) {
      if (server.port === port && path !== projectPath) {
        return { success: false, error: `Port ${port} is already in use by another project` }
      }
    }

    try {
      const server = http.createServer((req, res) => {
        // No CORS headers needed - server binds to localhost only (127.0.0.1)
        // and is not intended to be accessed from web pages

        if (req.method === 'POST' && req.url === '/prompt') {
          // Rate limiting check
          const clientIp = req.socket.remoteAddress || 'unknown'
          if (!this.checkRateLimit(clientIp)) {
            res.writeHead(429, { 'Content-Type': 'application/json' })
            res.end(JSON.stringify({
              success: false,
              error: 'Rate limit exceeded. Maximum 10 requests per minute.'
            }))
            return
          }

          // Periodically clean up stale rate limit entries
          if (Math.random() < 0.1) {
            this.cleanupRateLimitMap()
          }

          let body = ''
          let bodySizeExceeded = false
          req.on('data', chunk => {
            body += chunk
            // Check body size limit to prevent DoS attacks
            if (body.length > MAX_BODY_SIZE) {
              bodySizeExceeded = true
              res.writeHead(413, { 'Content-Type': 'application/json' })
              res.end(JSON.stringify({ success: false, error: 'Request body too large' }))
              req.destroy()
            }
          })
          req.on('error', (e) => {
            console.error('Request error:', e)
            res.writeHead(500, { 'Content-Type': 'application/json' })
            res.end(JSON.stringify({ success: false, error: 'Request error' }))
          })
          req.on('end', async () => {
            // Skip processing if body size limit was exceeded
            if (bodySizeExceeded) return
            try {
              const data = JSON.parse(body)
              const prompt = data.prompt || data.message || data.text || ''

              if (!prompt) {
                res.writeHead(400, { 'Content-Type': 'application/json' })
                res.end(JSON.stringify({ success: false, error: 'No prompt provided' }))
                return
              }

              if (this.promptHandler) {
                // Get session mode from project settings or request body
                const requestedMode = data.sessionMode as SessionMode | undefined
                const sessionMode = requestedMode || this.sessionModeGetter?.(projectPath) || 'existing'

                try {
                  const result = await this.promptHandler(projectPath, prompt, sessionMode)
                  if (result.success) {
                    res.writeHead(200, { 'Content-Type': 'application/json' })
                    res.end(JSON.stringify(result))
                  } else {
                    res.writeHead(404, { 'Content-Type': 'application/json' })
                    res.end(JSON.stringify(result))
                  }
                } catch (handlerError: any) {
                  res.writeHead(500, { 'Content-Type': 'application/json' })
                  res.end(JSON.stringify({ success: false, error: handlerError.message || 'Handler error' }))
                }
              } else {
                res.writeHead(500, { 'Content-Type': 'application/json' })
                res.end(JSON.stringify({ success: false, error: 'No prompt handler configured' }))
              }
            } catch (e) {
              res.writeHead(400, { 'Content-Type': 'application/json' })
              res.end(JSON.stringify({ success: false, error: 'Invalid JSON' }))
            }
          })
        } else if (req.method === 'GET' && req.url === '/status') {
          res.writeHead(200, { 'Content-Type': 'application/json' })
          res.end(JSON.stringify({
            success: true,
            project: projectPath,
            message: 'API server running'
          }))
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' })
          res.end(JSON.stringify({
            success: false,
            error: 'Not found',
            endpoints: {
              'POST /prompt': 'Send a prompt to the terminal. Body: { "prompt": "your message" }',
              'GET /status': 'Check server status'
            }
          }))
        }
      })

      server.on('error', (e: NodeJS.ErrnoException) => {
        console.error(`API server error on port ${port}:`, e.message)
        this.servers.delete(projectPath)
      })

      server.listen(port, '127.0.0.1', () => {
        console.log(`API server started on port ${port} for project: ${projectPath}`)
      })

      this.servers.set(projectPath, { server, port, projectPath })
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  }

  stop(projectPath: string): void {
    const apiServer = this.servers.get(projectPath)
    if (apiServer) {
      apiServer.server.close()
      this.servers.delete(projectPath)
      console.log(`API server stopped for project: ${projectPath}`)
    }
  }

  stopAll(): void {
    for (const [projectPath] of this.servers) {
      this.stop(projectPath)
    }
  }

  isRunning(projectPath: string): boolean {
    return this.servers.has(projectPath)
  }

  getPort(projectPath: string): number | undefined {
    return this.servers.get(projectPath)?.port
  }
}

