    76→    // Validate port is a number and within valid range (excluding privileged ports)
    77→    if (!Number.isInteger(port) || port < 1024 || port > 65535) {
    78→      return { success: false, error: 'Invalid port: must be an integer between 1024 and 65535' }
    79→    }
    80→
    81→    // Stop existing server for this project if any
    82→    this.stop(projectPath)
    83→
    84→    // Check if port is already in use by another project
    85→    for (const [path, server] of this.servers) {
    86→      if (server.port === port && path !== projectPath) {
    87→        return { success: false, error: `Port ${port} is already in use by another project` }
    88→      }
    89→    }
    90→
    91→    try {
    92→      const server = http.createServer((req, res) => {
    93→        // No CORS headers needed - server binds to localhost only (127.0.0.1)
    94→        // and is not intended to be accessed from web pages
    95→
    96→        if (req.method === 'POST' && req.url === '/prompt') {
    97→          // Rate limiting check
    98→          const clientIp = req.socket.remoteAddress || 'unknown'
    99→          if (!this.checkRateLimit(clientIp)) {
   100→            res.writeHead(429, { 'Content-Type': 'application/json' })
   101→            res.end(JSON.stringify({
   102→              success: false,
   103→              error: 'Rate limit exceeded. Maximum 10 requests per minute.'
   104→            }))
   105→            return
   106→          }
   107→
   108→          // Periodically clean up stale rate limit entries
   109→          if (Math.random() < 0.1) {
   110→            this.cleanupRateLimitMap()
   111→          }
   112→
   113→          let body = ''
   114→          let bodySizeExceeded = false
   115→          req.on('data', chunk => {
   116→            body += chunk
   117→            // Check body size limit to prevent DoS attacks
   118→            if (body.length > MAX_BODY_SIZE) {
   119→              bodySizeExceeded = true
   120→              res.writeHead(413, { 'Content-Type': 'application/json' })
   121→              res.end(JSON.stringify({ success: false, error: 'Request body too large' }))
   122→              req.destroy()
   123→            }
   124→          })
   125→          req.on('error', (e) => {
   126→            console.error('Request error:', e)
   127→            res.writeHead(500, { 'Content-Type': 'application/json' })
   128→            res.end(JSON.stringify({ success: false, error: 'Request error' }))
   129→          })
   130→          req.on('end', async () => {
   131→            // Skip processing if body size limit was exceeded
