   143→              if (this.promptHandler) {
   144→                // Get session mode from project settings or request body
   145→                const requestedMode = data.sessionMode as SessionMode | undefined
   146→                const sessionMode = requestedMode || this.sessionModeGetter?.(projectPath) || 'existing'
   147→
   148→                try {
   149→                  const result = await this.promptHandler(projectPath, prompt, sessionMode)
   150→                  if (result.success) {
   151→                    res.writeHead(200, { 'Content-Type': 'application/json' })
   152→                    res.end(JSON.stringify(result))
   153→                  } else {
   154→                    res.writeHead(404, { 'Content-Type': 'application/json' })
