   157→                } catch (handlerError: any) {
   158→                  res.writeHead(500, { 'Content-Type': 'application/json' })
   159→                  res.end(JSON.stringify({ success: false, error: handlerError.message || 'Handler error' }))
   160→                }
   161→              } else {
