   183→          }
   184→
   185→          // Call global callbacks
   186→          for (const cb of this.globalDataCallbacks) {
   187→            cb(message.ptyId, data)
   188→          }
   189→        }
   190→        break
   191→
   192→      case 'terminal:exit':
   193→        if (message.ptyId && message.payload) {
   194→          const code = (message.payload as { code: number }).code
   195→
   196→          // Call ptyId-specific callbacks
   197→          const exitCallbacks = this.terminalExitCallbacks.get(message.ptyId)
   198→          if (exitCallbacks) {
   199→            for (const cb of exitCallbacks) {
   200→              cb(code)
