   264→  resizeTerminal(ptyId: string, cols: number, rows: number): void {
   265→    this.send({
   266→      type: 'terminal:resize',
   267→      ptyId,
   268→      payload: { cols, rows },
   269→      timestamp: Date.now()
   270→    })
   271→  }
   272→
   273→  /**
   274→   * Register callback for terminal data
   275→   */
   276→  onTerminalData(ptyId: string, callback: (data: string) => void): () => void {
   277→    if (!this.terminalDataCallbacks.has(ptyId)) {
