   286→      if (callbacks) {
   287→        callbacks.delete(callback)
   288→        if (callbacks.size === 0) {
   289→          this.terminalDataCallbacks.delete(ptyId)
   290→          this.unsubscribeFromTerminal(ptyId)
   291→        }
   292→      }
   293→    }
   294→  }
