   318→   */
   319→  onAnyTerminalData(callback: TerminalDataCallback): () => void {
   320→    this.globalDataCallbacks.add(callback)
   321→    return () => this.globalDataCallbacks.delete(callback)
   322→  }
   323→
   324→  /**
   325→   * Register global callback for all terminal exits
   326→   */
   327→  onAnyTerminalExit(callback: TerminalExitCallback): () => void {
   328→    this.globalExitCallbacks.add(callback)
   329→    return () => this.globalExitCallbacks.delete(callback)
   330→  }
   331→
   332→  /**
   333→   * Register callback for connection events
   334→   */
   335→  onConnect(callback: () => void): () => void {
   336→    this.onConnectCallbacks.add(callback)
   337→    return () => this.onConnectCallbacks.delete(callback)
   338→  }
   339→
   340→  /**
   341→   * Register callback for disconnection events
   342→   */
   343→  onDisconnect(callback: () => void): () => void {
   344→    this.onDisconnectCallbacks.add(callback)
   345→    return () => this.onDisconnectCallbacks.delete(callback)
   346→  }
   347→
   348→  /**
   349→   * Schedule reconnection attempt
   350→   */
   351→  private scheduleReconnect(): void {
   352→    if (this.reconnectTimer) {
   353→      return
   354→    }
   355→
   356→    const delay = this.reconnectDelay * Math.pow(2, this.reconnectAttempts)
   357→    console.log(`[WS] Scheduling reconnect in ${delay}ms (attempt ${this.reconnectAttempts + 1})`)
   358→
   359→    this.reconnectTimer = setTimeout(() => {
